pub const TaggedModuleHTTPProxy = HTTPProxyModule;

pub const TaggedModuleIP = IPModule;

pub const TaggedModuleOnDemand = OnDemandModule;

pub const TaggedModuleOpenVPN = OpenVPNModule;

pub const TaggedModuleWireGuard = WireGuardModule;

pub const TaggedModule = union(enum) {
    DNS: DNSModule,
    HTTPProxy: HTTPProxyModule,
    IP: IPModule,
    OnDemand: OnDemandModule,
    OpenVPN: OpenVPNModule,
    WireGuard: WireGuardModule,

    pub fn parse(allocator: std.mem.Allocator, text: []const u8) DecodeError!TaggedModule {
        return parseWithErrorInfo(allocator, text, null);
    }

    pub fn parseWithErrorInfo(allocator: std.mem.Allocator, text: []const u8, error_info: ?*JsonErrorInfo) DecodeError!TaggedModule {
        resetJsonErrorInfo(error_info);
        var parsed = try util.parseJsonValue(allocator, text);
        defer parsed.deinit();
        return parseValueWithErrorInfo(allocator, parsed.value, error_info);
    }

    pub fn parseValue(allocator: std.mem.Allocator, value: std.json.Value) DecodeError!TaggedModule {
        return parseValueWithErrorInfo(allocator, value, null);
    }

    pub fn parseValueWithErrorInfo(allocator: std.mem.Allocator, value: std.json.Value, error_info: ?*JsonErrorInfo) DecodeError!TaggedModule {
        resetJsonErrorInfo(error_info);
        const object = objectValue(value) orelse return error.InvalidModel;
        const raw_discriminator = object.get("type") orelse {
            setJsonErrorKey(error_info, "type");
            return error.InvalidModel;
        };
        const raw_type = stringValue(raw_discriminator) orelse {
            setJsonErrorKey(error_info, "type");
            return error.InvalidModel;
        };
        if (std.mem.eql(u8, raw_type, "DNS")) return .{ .DNS = try parseJsonField(DNSModule, allocator, object, "value", error_info) };
        if (std.mem.eql(u8, raw_type, "HTTPProxy")) return .{ .HTTPProxy = try parseJsonField(HTTPProxyModule, allocator, object, "value", error_info) };
        if (std.mem.eql(u8, raw_type, "IP")) return .{ .IP = try parseJsonField(IPModule, allocator, object, "value", error_info) };
        if (std.mem.eql(u8, raw_type, "OnDemand")) return .{ .OnDemand = try parseJsonField(OnDemandModule, allocator, object, "value", error_info) };
        if (std.mem.eql(u8, raw_type, "OpenVPN")) return .{ .OpenVPN = try parseJsonField(OpenVPNModule, allocator, object, "value", error_info) };
        if (std.mem.eql(u8, raw_type, "WireGuard")) return .{ .WireGuard = try parseJsonField(WireGuardModule, allocator, object, "value", error_info) };
        setJsonErrorKey(error_info, "type");
        return error.UnsupportedModel;
    }

    pub fn clone(self: @This(), allocator: std.mem.Allocator) DecodeError!@This() {
        const encoded = try util.encodeJsonValue(allocator, self);
        defer allocator.free(encoded);
        return parse(allocator, encoded);
    }

    pub fn deinit(self: *@This(), allocator: std.mem.Allocator) void {
        switch (self.*) {
            .DNS => |*value| deinitJson(DNSModule, allocator, value),
            .HTTPProxy => |*value| deinitJson(HTTPProxyModule, allocator, value),
            .IP => |*value| deinitJson(IPModule, allocator, value),
            .OnDemand => |*value| deinitJson(OnDemandModule, allocator, value),
            .OpenVPN => |*value| deinitJson(OpenVPNModule, allocator, value),
            .WireGuard => |*value| deinitJson(WireGuardModule, allocator, value),
        }
    }

    pub fn jsonStringify(self: @This(), jw: anytype) JsonStringifyError!void {
        try jw.beginObject();
        switch (self) {
            .DNS => |value| {
                try jw.objectField("type");
                try jw.write("DNS");
                try jw.objectField("value");
                try writeJson(jw, value);
            },
            .HTTPProxy => |value| {
                try jw.objectField("type");
                try jw.write("HTTPProxy");
                try jw.objectField("value");
                try writeJson(jw, value);
            },
            .IP => |value| {
                try jw.objectField("type");
                try jw.write("IP");
                try jw.objectField("value");
                try writeJson(jw, value);
            },
            .OnDemand => |value| {
                try jw.objectField("type");
                try jw.write("OnDemand");
                try jw.objectField("value");
                try writeJson(jw, value);
            },
            .OpenVPN => |value| {
                try jw.objectField("type");
                try jw.write("OpenVPN");
                try jw.objectField("value");
                try writeJson(jw, value);
            },
            .WireGuard => |value| {
                try jw.objectField("type");
                try jw.write("WireGuard");
                try jw.objectField("value");
                try writeJson(jw, value);
            },
        }
        try jw.endObject();
    }
};

